&lt;p&gt;&lt;strong&gt;उत्तर -&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;ओठ&lt;/strong&gt;&amp;nbsp;या&amp;nbsp;शब्दाचा समानार्थी शब्द&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;अधर&lt;/strong&gt; हा होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;समानार्थी शब्द&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एखाद्या शब्दासाठी त्याच अर्थाचा दुसरा शब्द म्हणजे&amp;nbsp;समानार्थी शब्द&amp;nbsp;होय.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;वदन&lt;/strong&gt;,&amp;nbsp;&lt;strong&gt;आनन&lt;/strong&gt; हे &lt;strong&gt;तोंड&lt;/strong&gt; या शब्दाचे&amp;nbsp;समानार्थी शब्द आहेत.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;नयन&lt;/strong&gt; हा &lt;strong&gt;डोळा&lt;/strong&gt; या शब्दाचा&amp;nbsp;समानार्थी शब्द आहे.&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;आस्था&lt;/strong&gt;&amp;nbsp;या शब्दाचा विरुध्दार्थी शब्द&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;अनास्था&lt;/strong&gt; हा होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विरुद्धार्थी&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;शब्द&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जे शब्द कोणत्याही शब्दाला विरुद्ध अर्थ देतात अशा शब्दांना विरुद्धार्थी शब्द असे म्हटले जाते.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;अनिच्छा&lt;/strong&gt;&amp;nbsp;या शब्दाचा विरूध्दार्थी शब्द &lt;strong&gt;इच्छा&lt;/strong&gt;&amp;nbsp;हा होईल.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;अवधान&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;या शब्दाचा विरूध्दार्थी शब्द&amp;nbsp;&lt;strong&gt;अनवधान&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;हा होईल.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;अनादर&lt;/strong&gt;&amp;nbsp;या शब्दाचा विरूध्दार्थी शब्द &lt;strong&gt;आदर&lt;/strong&gt;&amp;nbsp;हा होईल.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;गोड&lt;/strong&gt;&amp;nbsp;या&amp;nbsp;शब्दाचा समानार्थी शब्द&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;मधुर&lt;/strong&gt; हा होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;समानार्थी शब्द&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एखाद्या शब्दासाठी त्याच अर्थाचा दुसरा शब्द म्हणजे&amp;nbsp;समानार्थी शब्द&amp;nbsp;होय.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;चव&lt;/strong&gt;&amp;nbsp;या&amp;nbsp;शब्दाचे समानार्थी शब्द आस्वाद, गोडी, रुची, आवड हे होतील.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;गोड&lt;/strong&gt;&amp;nbsp;या&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;शब्दाचा विरुद्धार्थी शब्द&amp;nbsp;&lt;strong&gt;कडू&lt;/strong&gt; हा होईल.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;ताटा खालचे मांजर&lt;/strong&gt;&amp;nbsp;या शब्दार्थाचा वाक्यात उपयोग झालेले&amp;nbsp;योग्य विधान&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;स्वाभिमानी व्यक्तीला कोणाच्याही ताटाखालचे मांजर व्हायला आवडत नाही&lt;/strong&gt; हे होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;अलंकारिक शब्द&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्याप्रमाणे अलंकार,&amp;nbsp;पोशाख,&amp;nbsp;केशरचना या मानवाच्या सौंदर्यात भर&amp;nbsp;घालतात,&amp;nbsp;त्याचप्रमाणे&amp;nbsp;&lt;strong&gt;म्हणी&lt;/strong&gt;,&amp;nbsp;&lt;strong&gt;वाक्प्रचार&lt;/strong&gt;,&amp;nbsp;&lt;strong&gt;अलंकारिक शब्द&lt;/strong&gt;&amp;nbsp;भाषेचे सौंदर्य वाढवतात.&lt;/li&gt;
	&lt;li&gt;कमी शब्दांत व्यापक अर्थ&amp;nbsp;&lt;strong&gt;अलंकारिक&lt;/strong&gt;&amp;nbsp;शब्दांतून व्यक्त केला जातो.&amp;nbsp;अलंकारिक शब्द हे भाषा समृद्ध बनवतात.&lt;/li&gt;
	&lt;li style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;ताटा खालचे मांजर&lt;/span&gt;&amp;nbsp;याचा अर्थ&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;दुसऱ्याच्या म्हणण्यानुसार वागणारा&lt;/span&gt;&amp;nbsp;असा होतो.&lt;/li&gt;
	&lt;li style=&quot;color: rgb(33, 37, 41);&quot;&gt;स्वाभिमानी व्यक्तीला कोणाच्याही ताटाखालचे मांजर व्हायला आवडत नाही याचा अर्थ&amp;nbsp;स्वाभिमानी व्यक्ती&amp;nbsp;दुसऱ्याच्या म्हणण्यानुसार वागत नाही.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;सुलक्षणी&lt;/strong&gt;&amp;nbsp;या शब्दाचा विरूध्दार्थी शब्द&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;अवलक्षणी&lt;/strong&gt; हा होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विरुद्धार्थी&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;शब्द&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जे शब्द कोणत्याही शब्दाला विरुद्ध अर्थ देतात अशा शब्दांना विरुद्धार्थी शब्द असे म्हटले जाते.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;अवनती&lt;/strong&gt;&amp;nbsp;या शब्दाचा विरूध्दार्थी शब्द &lt;strong&gt;प्रगती&lt;/strong&gt;&amp;nbsp;हा होईल.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;आकर्षक&lt;/strong&gt;&amp;nbsp;या शब्दाचा विरूध्दार्थी शब्द &lt;strong&gt;अनाकर्षक&lt;/strong&gt;&amp;nbsp;हा होईल.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;शुभशकुनी&lt;/strong&gt;&amp;nbsp;या शब्दाचा विरूध्दार्थी शब्द &lt;strong&gt;अपशकुनी&lt;/strong&gt;&amp;nbsp;हा होईल.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;स्मृतीचित्रे&lt;/strong&gt; हे&amp;nbsp;आत्मचरीत्र&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;लक्ष्मीबाई टिळक&lt;/strong&gt; यांनी&amp;nbsp;&lt;/span&gt;लिहिले&amp;nbsp;आहे.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;लक्ष्मीबाई टिळक&lt;/strong&gt;&amp;nbsp;या&amp;nbsp;&lt;span title=&quot;मराठी भाषा&quot;&gt;मराठी भाषेतील&lt;/span&gt;&amp;nbsp;लेखिका होत्या. लग्नापूर्वीचे त्यांचे नाव&amp;nbsp;मनकर्णिका गोखले&amp;nbsp;होते. वयाच्या १५ व्या वर्षी लक्ष्मीबाईचा विवाह&amp;nbsp;&lt;span title=&quot;नारायण वामन टिळक&quot;&gt;नारायण वामन टिळक &lt;/span&gt;यांच्याशी झाला. लक्ष्मीबाई आपल्या&amp;nbsp;&lt;span title=&quot;स्मृतिचित्रे&quot;&gt;स्मृतिचित्रे&lt;/span&gt;&amp;nbsp;या आत्मचरित्रासाठी प्रसिद्ध आहेत. &lt;span title=&quot;महाराष्ट्र साहित्य परिषद&quot;&gt;महाराष्ट्र सरकारतर्फे&lt;/span&gt;&amp;nbsp;लक्ष्मीबाई टिळक यांच्या नावाचा पुरस्कार एखाद्या आत्मकथनात्मक पुस्तकाला किंवा आत्मचरित्राला दिला जातो.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;सुनीता देशपांडे&lt;/strong&gt;&amp;nbsp;पूर्वाश्रमीचे नाव&amp;nbsp;सुनीता ठाकूर, या&amp;nbsp;&lt;span title=&quot;मराठी&quot;&gt;मराठी&lt;/span&gt;&amp;nbsp;लेखिका व सामाजिक कार्यकर्त्या होत्या. मराठी साहित्यिक&amp;nbsp;&lt;span title=&quot;पु. ल. देशपांडे&quot;&gt;पु. ल. देशपांडे&lt;/span&gt;&amp;nbsp;त्यांचे पती होते. त्यांनी पुलंबरोबर अनेक नाटकांत काम केले. तसेच &amp;#39;वंदेमातरम्&amp;#39; या&amp;nbsp;&lt;span title=&quot;राम गबाले&quot;&gt;राम गबाले&lt;/span&gt;&amp;nbsp;दिग्दर्शित चित्रपटातील त्यांची भूमिका अतिशय गाजली होती. &amp;#39;राजमाता जिजाबाई&amp;#39; हा एकपात्री प्रयोगही त्यांनी रंगवला होता. पुलंच्या &amp;#39;सुदर मी होणार&amp;#39; मधील दीदीराजे ही मध्यवर्ती भूमिका सुनिताबाईंनी साकारली होती. &lt;strong&gt;आहे मनोहर तरी&lt;/strong&gt; हे त्यांचे &lt;strong&gt;आत्मचरित्र&lt;/strong&gt; आहे. प्रिय जी. ए हा त्यांचा पत्रसंग्रह आहे.&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;कुसुमावती देशपांडे&lt;/strong&gt;&amp;nbsp;या मराठीतील लेखिका व समालोचक होत्या. त्यांनी मराठी लघुकथेला नवीन रूप आणि चैतन्य बहाल केले.&amp;nbsp;नवी दिल्ली&amp;nbsp;येथे त्या आकाशवाणीवरील स्त्रिया आणि मुलांच्या कार्यक्रमाच्या एक प्रमुख निर्मात्या होत्या. &amp;quot;पासंग&amp;quot; या १९५४ साली प्रकाशित झालेल्या संग्रहात त्यांच्या लेखांचे संकलन आहे. दीपकळी, दीपमाळ, मोळी, दीपदान, कुसुमानिल हे त्यांचे प्रकाशित साहित्य आहे.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;बहिणाबाई नथुजी चौधरी&lt;/strong&gt;&amp;nbsp;या &lt;span title=&quot;मराठी&quot;&gt;मराठी&lt;/span&gt;&amp;nbsp;कवयित्री होत्या. बहिणाबाईंच्या कविता खानदेशातील त्यांच्या मातृबोलीत, रचिलेल्या आहेत. त्यांच्या कवितांचे विषय माहेर, संसार; शेतीची साधने, कापणी, मळणी इ. कृषिजीवनातील विविध प्रसंग; अक्षय्य तृतीया, पोळा, पाडवा इत्यादी सणसोहळे; काही परिचित व्यक्ती, असे आहेत. बहिणाबाईंच्या काव्याचा इंग्रजी अनुवाद &amp;rsquo;फ्रॅग्रन्स ऑफ दि अर्थ&amp;rsquo; या कवितासंग्रहाच्या रूपाने प्रकाशित झाला आहे.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;चिमणी चिवचिवते. हे&amp;nbsp;&lt;strong style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); text-align: var(--bs-body-text-align);&quot;&gt;अकर्मक&lt;/strong&gt;&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;strong style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); text-align: var(--bs-body-text-align);&quot;&gt;कर्तरी&lt;/strong&gt;&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt;&amp;nbsp;प्रयोगाचे उदाहरण आहे.&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span lang=&quot;HI&quot; style=&quot; line-height: 107%; &quot;&gt;वरील वाक्यात&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;चिमणी&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;हा &lt;strong&gt;कर्ता&lt;/strong&gt; आहे आणि कर्त्याला प्रत्यय नसून तो प्रथमेत आहे तसेच या वाक्यात कर्म आलेले नाही म्हणून हे वाक्य&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;अकर्मक&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;कर्तरी&lt;/span&gt;&lt;span style=&quot; line-height: 107%; &quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;प्रयोगाचे होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;कर्तरी प्रयोग -&lt;/strong&gt;&amp;nbsp;जेव्हा वाक्यात क्रियापदाचे रूप हे कर्त्याच्या लिंग,&amp;nbsp;पुरुष आणि&amp;nbsp;वचनानुसार बदलत असेल तर त्या प्रयोगास&amp;nbsp;कर्तरी प्रयोग&amp;nbsp;असे म्हणतात.&amp;nbsp;कर्तरी&amp;nbsp;प्रयोगात क्रियापद बहुधा वर्तमानकाळी असते आणि कर्ता&amp;nbsp;&lt;strong&gt;प्रथमान्त&lt;/strong&gt;&amp;nbsp;असतो तसेच कर्त्याला प्रत्यय नसतो.&amp;nbsp;उदा.&amp;nbsp;विजय निबंध लिहितो.&lt;/p&gt;

&lt;p&gt;कर्तरी प्रयोगाचे&amp;nbsp;&lt;strong&gt;दोन&lt;/strong&gt;&amp;nbsp;उपप्रकार पडतात.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;सकर्मक कर्तरी प्रयोग&lt;/li&gt;
	&lt;li&gt;अकर्मक कर्तरी प्रयोग&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;सकर्मक कर्तरी प्रयोग&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या कर्तरी प्रयोगाच्या वाक्यात कर्म आलेले असेल तेव्हा त्यास&amp;nbsp;सकर्मक कर्तरी प्रयोग&amp;nbsp;असे म्हणतात.&amp;nbsp;सकर्मक कर्तरी प्रयोगात कर्म असावेच लागते आणि ते&amp;nbsp;प्रथमान्&amp;zwj;त किंवा द्वितीयान्&amp;zwj;त&amp;nbsp;असते.&amp;nbsp;&amp;nbsp;उदा. तो गाणे गातो.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;अकर्मक कर्तरी प्रयोग&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या कर्तरी प्रयोगाच्या वाक्यात जेव्हा कर्म आलेले नसते तेव्हा त्यास&amp;nbsp;अकर्मक कर्तरी प्रयोग&amp;nbsp;असे म्हणतात.&amp;nbsp;अकर्मक कर्तरी प्रयोगात&amp;nbsp;क्रियापदाचे रूप हे कर्त्याच्या लिंग,&amp;nbsp;पुरुष आणि&amp;nbsp;वचनानुसार बदलते म्हणजेच&amp;nbsp;&lt;strong&gt;कर्ता&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;धातुरूपेश असतो&lt;/strong&gt;.&amp;nbsp;उदा. सूर्य उगवला.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;प्रयोग&lt;/strong&gt;&amp;nbsp;- कर्त्याची व कर्माची क्रियापदाशी जी जुळणी,&amp;nbsp;ठेवण किंवा रचना असते तिला व्याकरणात प्रयोग असे म्हणतात.&amp;nbsp;प्रयोग ओळखण्&amp;zwj;यासाठी कर्ता,&amp;nbsp;कर्म व क्रियापद यांची आवश्यकता असते.प्रयोगाचे प्रमुख&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार पडतात.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;कर्तरी प्रयोग&lt;/li&gt;
	&lt;li&gt;कर्मणी प्रयोग&lt;/li&gt;
	&lt;li&gt;भावे प्रयोग&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;कर्मणी प्रयोग&lt;/strong&gt;&amp;nbsp;- कर्मणी प्रयोगात क्रियापदाचे रूप कर्माच्या लिंग किवा वचनानुसार बदलते म्हणून त्यास&amp;nbsp;कर्मणी प्रयोग&amp;nbsp;असे म्हणतात. कर्मणी&amp;nbsp;प्रयोगात कर्माची आवश्&amp;zwj;यकता असते व ते प्रथमेतच असते. कर्मणी&amp;nbsp;प्रयोगात&amp;nbsp;कर्त्याला विभक्तीप्रत्यय असतो तर कर्माला नसतो. कर्मणी&amp;nbsp;प्रयोगात क्रियापद बहुधा भूतकाळी असते. उदा. मधूने बैल बांधला.&lt;/p&gt;

&lt;p&gt;कर्म नसेल तर&amp;nbsp;कर्मणी प्रयोग कधीच नसतो.&lt;/p&gt;

&lt;p&gt;कर्मणी प्रयोगाचे&amp;nbsp;&lt;strong&gt;पाच&lt;/strong&gt;&amp;nbsp;उपप्रकार पडतात.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;प्राचीन कर्मणी प्रयोग / पुराण कर्मणी प्रयोग&lt;/li&gt;
	&lt;li&gt;नवीन कर्मणी प्रयोग / कर्मकर्तरी प्रयोग&lt;/li&gt;
	&lt;li&gt;समापन कर्मणी प्रयोग&lt;/li&gt;
	&lt;li&gt;शक्य कर्मणी प्रयोग&lt;/li&gt;
	&lt;li&gt;प्रधानकर्तृक&amp;nbsp;कर्मणी प्रयोग&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;समापन कर्मणी प्रयोग&lt;/strong&gt;&amp;nbsp;- या कर्मणी प्रयोगातून कृती पूर्ण झाल्याचे सूचित केले जाते. क्रियापद शक्यतो ऊन/हुन + झाला/झाली/झाले प्रकारचे असते. उदा. त्याचा आंबा खाऊन झाला.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;भावे प्रयोग&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;जेव्हा कर्त्याच्या किवा कर्माच्या लिंग किवा वचनात बदल करूनही क्रियापद बदलत नाही तेव्हा त्या प्रयोगास&amp;nbsp;भावे प्रयोग&amp;nbsp;असे म्हणतात.&amp;nbsp;या प्रयोगात कर्ता व कर्माला प्रत्यय असतो.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;भावे प्रयोगाचे&amp;nbsp;&lt;strong&gt;सकर्मक&lt;/strong&gt;&amp;nbsp;व&amp;nbsp;&lt;strong&gt;अकर्मक&lt;/strong&gt;&amp;nbsp;असे दोन प्रकार पडतात&lt;span dir=&quot;RTL&quot;&gt;.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;अकर्मक भावे प्रयोग&lt;/strong&gt;&amp;nbsp;- ज्या भावे प्रयोगाच्या वाक्यात कर्म आलेले नसल्यास त्यास&amp;nbsp;अकर्मक भावे प्रयोग&amp;nbsp;असे म्हणतात.&amp;nbsp;अकर्मक भावे प्रयोगात क्रियापद विध्यर्थीच असते तसेच अकर्मक शक्यार्थ क्रियापदांचा नेहमीच भावे प्रयोग असतो.&amp;nbsp;उदा. त्याला आता पळवते.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;सकर्मक भावे प्रयोग&lt;/strong&gt;&amp;nbsp;- ज्या भावे प्रयोगाच्या वाक्यात कर्म आलेले असल्यास त्यास&amp;nbsp;सकर्मक भावे प्रयोग&amp;nbsp;म्हणतात.&amp;nbsp;या प्रयोगात कर्त्याला शक्यतो तृतीयेचा ने/नी प्रत्यय असतो तसेच कर्मालाही प्रत्यय असतो. उदा. श्यामने गाईला बांधले.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;मीठभाकर&lt;/strong&gt; हे&amp;nbsp;&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt;&lt;strong&gt;द्वंद्व समासाचे&lt;/strong&gt; उदाहरण आहे आणि ते&amp;nbsp;&lt;/span&gt;&lt;span lang=&quot;MR&quot; style=&quot; line-height: 107%; &quot;&gt;&lt;strong&gt;समाहार&lt;/strong&gt; द्वंद्व&amp;nbsp;&lt;/span&gt;या उपप्रकारात मोडते.&lt;/p&gt;

&lt;p&gt;मीठभाकर&amp;nbsp;या सामासिक शब्दात&amp;nbsp;मीठ, भाकरी&amp;nbsp;व इतर&amp;nbsp;साधे खाद्यपदार्थ&amp;nbsp;यांचा&amp;nbsp;अंतर्भाव होतो म्हणून हे&amp;nbsp;&lt;strong&gt;समाहार द्वंद्व&lt;/strong&gt; समासाचे उदाहरण आहे&lt;span dir=&quot;RTL&quot;&gt;.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विग्रह&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;मीठ, भाकरी&amp;nbsp;व इतर&amp;nbsp;साधे खाद्यपदार्थ&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;द्वंद्व समास&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या समासातील दोन्ही पद अर्थदृष्टया समान दर्जाचे असतात&amp;nbsp;त्यास&amp;nbsp;व्दंव्द समास&amp;nbsp;असे म्हणतात. या समासातील पदे आणि,&amp;nbsp;अथवा,&amp;nbsp;व,&amp;nbsp;किंवा या उभयान्वयी अव्ययांनी जोडलेली असतात. उदा. पापपुण्य - पाप आणि पुण्य&lt;/p&gt;

&lt;p&gt;व्दंव्द समासाचे पुढील&amp;nbsp;&lt;strong&gt;तीन&lt;/strong&gt;&amp;nbsp;प्रकार पडतात.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;इतरेतर व्दंव्द समास&lt;/li&gt;
	&lt;li&gt;वैकल्पिक व्दंव्द समास&lt;/li&gt;
	&lt;li&gt;समाहार व्दंव्द समास&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;इतरेतर द्वंद्व समास&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या समासाचा विग्रह करतांना आणि, व&amp;nbsp;या&amp;nbsp;समुच्चय बोधक उभयान्वयी अव्ययांचा उपयोग करावा लागतो&amp;nbsp;त्यास&amp;nbsp;इतरेतर व्दंव्द समास&amp;nbsp;असे म्हणतात. उदा.&amp;nbsp;बहीणभाऊ -&amp;nbsp;बहीण आणि भाऊ&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;वैकल्पिक द्वंद्व समास&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या समासाचा विग्रह करतांना किंवा, अथवा, वा या विकल्प बोधक&amp;nbsp;उभयान्वयी&amp;nbsp;अव्ययांचा उपयोग करावा लागतो त्यास&amp;nbsp;वैकल्पिक व्दंव्द समास&amp;nbsp;असे म्हणतात.&amp;nbsp;उदा.&amp;nbsp;न्यायान्याय -&amp;nbsp;न्याय अथवा अन्याय&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;समाहार द्वंद्व समास&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या समासातील पदांचा विग्रह करतांना त्यातील पदांचा अर्थशिवाय त्याच जातीच्या इतर पदार्थाचाही त्यात समावेश केलेला असतो त्यास समाहार व्दंव्द समास असे म्हणतात.उदा.&amp;nbsp;केरकचरा&amp;nbsp;- केर, कचरा व इतर टाकाऊ पदार्थ&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;अव्ययीभाव समास&lt;/strong&gt;&amp;nbsp;- ज्या समासात पहिला शब्द मुख्य असतो व त्या तयार झालेल्या सामासिक शब्दांचा उपयोग क्रियाविशेषणासारखा केला जातो त्यास अव्ययीभाव समास असे म्हणतात.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;उदा.&amp;nbsp;प्रतिक्षण&amp;nbsp;-&amp;nbsp;प्रत्येक क्षणाला,&amp;nbsp;यथाक्रम - क्रमाप्रमाणे,&amp;nbsp;आमरण - मरेपर्यंत&amp;nbsp;&lt;/p&gt;

&lt;p&gt;वरील उदाहरणात प्रति,&amp;nbsp;यथा&amp;nbsp;आ&amp;nbsp;हे संस्कृत भाषेतील उपसर्ग लागून तयार झालेले शब्द आहेत.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;बे, दर, बेला, गैर, बिन, हर, बर यांसारखे फारशी भाषेतील उपसर्ग लागून तयार झालेले शब्द&amp;nbsp;अव्ययीभाव समासाची&amp;nbsp;उदाहरणे आहेत.&lt;/p&gt;

&lt;p&gt;उदा. दरसाल - प्रत्येक वर्षी, बेशक - शंकेशिवाय, बिनचूक - चुकीशिवाय&lt;/p&gt;

&lt;p&gt;मराठी भाषेतील व्दिरुक्ती (पहिल्या शब्दांचीच पुनरावृत्ती) होऊन तयार झालेले&amp;nbsp;शब्द&amp;nbsp;हे सुद्धा&amp;nbsp;क्रियाविशेषणाप्रमाणे वापरले&amp;nbsp;जातत&amp;nbsp;म्हणून हे शब्द&amp;nbsp;अव्ययीभाव&amp;nbsp;समास या&amp;nbsp; प्रकारात मोडतात.&amp;nbsp;उदा. पानोपानी - प्रत्येक पानात, दारोदार - प्रत्येक दारी&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;तत्पुरुष समास&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या समासात दुसरे पद महत्वाचे असून समासाचा विग्रह करतांना गाळलेला शब्द&amp;nbsp;किंवा&amp;nbsp;विभक्ती प्रत्यय लिहावा लागतो, त्यास तत्पुरुष&amp;nbsp;समास&amp;nbsp;असे म्हणतात. थोडक्यात ज्या समासात&amp;nbsp;दूसरा शब्द प्रधान / महत्वाचा असतो&amp;nbsp;त्यास&amp;nbsp;तत्पुरुष समास&amp;nbsp;असे म्हणतात.&lt;/p&gt;

&lt;p&gt;तत्पुरुष समासाचे&amp;nbsp;&lt;strong&gt;सात&lt;/strong&gt;&amp;nbsp;उपप्रकार&amp;nbsp;पडतात.&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;विभक्ती&amp;nbsp;तत्पुरुष&amp;nbsp;समास&lt;/li&gt;
	&lt;li&gt;अलुक&amp;nbsp;तत्पुरुष&amp;nbsp;समास&lt;/li&gt;
	&lt;li&gt;उपपद&amp;nbsp;तत्पुरुष&amp;nbsp;समास&lt;/li&gt;
	&lt;li&gt;नञ&amp;nbsp;तत्पुरुष समास&lt;/li&gt;
	&lt;li&gt;कर्मधारय&amp;nbsp;तत्पुरुष समास&lt;/li&gt;
	&lt;li&gt;द्विगू समास&lt;/li&gt;
	&lt;li&gt;मध्यमपद लोपी समास​&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;strong&gt;द्विगू समास&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;ज्या कर्मधारय समासातील पहिले पद हे संख्याविशेषण असते व या सामासिक शब्दातून एक समूह सुचविला जातो त्यास द्विगू समास म्हणतात. उदा. सप्ताह - सात दिवसांचा समूह&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उत्तर -&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;गंमत&lt;/strong&gt; या&amp;nbsp;शब्दाचा समानार्थी शब्द&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;strong&gt;मौज&lt;/strong&gt; हा होईल.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;समानार्थी शब्द&lt;/strong&gt;&amp;nbsp;-&amp;nbsp;एखाद्या शब्दासाठी त्याच अर्थाचा दुसरा शब्द म्हणजे&amp;nbsp;समानार्थी शब्द&amp;nbsp;होय.&lt;/p&gt;

